void solve(int CASE)
{
	int n, m; cin >> n >> m;
	var g = vector<vector<pll>>(n + 1);
	var p = vector<tuple<ll, ll, ll>>();
	fa(i, 1, m) {
		ll u, v, w; cin >> u >> v >> w;
		p.pb({ u,v,w });
		g[u].pb({ v,w }), g[v].pb({ u,w });
	}

	var dis = Vec2<ll>(2, n + 1, LNF);
	var dij = [&](int s, vector<ll>& dis)->void {
		var vis = vector<int>(n + 1);
		var Q = priority_queue<pll, vector<pll>, greater<pll>>();
		Q.push({ dis[s] = 0, s });
		while (Q.size()) {
			var[d, now] = Q.top();
			Q.pop();
			if (vis[now])continue;
			vis[now] = 1;
			for (const var& [to, w] : g[now]) {
				if (dis[to] > max(dis[now], w)) {
					dis[to] = max(dis[now], w);
					Q.push({ dis[to], to });
				}
			}
		}
		};
	dij(1, dis[0]); // 算 1 -> u 的最大瓶颈路
	dij(n, dis[1]); // 算 n -> u 的最大瓶颈路

	ll ans = LNF;
	for (const var& [x, y, w] : p) {
		// 枚举边
		// w 为最大瓶颈路，max(dis[0][x], dis[1][y]) 为次大瓶颈路
		if (w >= max(dis[0][x], dis[1][y]))
			ans = min(ans, max(dis[0][x], dis[1][y]) + w);
		if (w >= max(dis[1][x], dis[0][y]))
			ans = min(ans, max(dis[1][x], dis[0][y]) + w);
	}
	if (ans == LNF)cout << -1 << endl;
	else cout << ans << endl;
	return;
}
